import logging

from geosat.gsvision.models import factory
from geosat.gsvision.models.model import Model, GsvisionPath
from geosat.gsvision.models.progress_notifier import IProgressNotifier
from pydantic import Field

from psanp.run import register_all_stages, run_psanp

logger = logging.getLogger(__name__)


class Psanp(Model):
    """A GSVision model to classify point clouds"""

    source: GsvisionPath = Field(
        description="Local or S3 path to the input point cloud (LAZ, LAS), or to a directory containing point clouds",
    )
    pipeline_file: GsvisionPath = Field(
        description="Local or S3 path path to the pipeline JSON file",
    )

    def run_model(self, progress_notifier: IProgressNotifier) -> None:
        progress_notifier.start(total_count=2)
        progress_notifier.update_state(step_index=0)
        run_psanp(self.pipeline_file, override={"source": self.source})
        progress_notifier.update_state(step_index=1)


def initialize() -> None:
    # PSANP Stages must be registered only once per Python process:
    register_all_stages()
    factory.register(Psanp.__name__, Psanp)
